<?php if (!defined('ABSPATH')) exit; get_header(); while (have_posts()) : the_post(); $origen = get_post_meta(get_the_ID(), '_origen', true); $destino = get_post_meta(get_the_ID(), '_destino', true); $fecha = get_post_meta(get_the_ID(), '_fecha_viaje', true); $hora = get_post_meta(get_the_ID(), '_hora_salida', true); $plazas = get_post_meta(get_the_ID(), '_plazas_disponibles', true); $precio = get_post_meta(get_the_ID(), '_precio_plaza', true); $conductor_id = get_the_author_meta('ID'); ?>
<div class="flavor-container py-8"><nav class="flex mb-6 text-sm"><ol class="inline-flex items-center space-x-2"><li><a href="<?php echo home_url('/'); ?>">Inicio</a></li><li><span class="mx-2">/</span></li><li><a href="<?php echo get_post_type_archive_link('carpooling'); ?>">Carpooling</a></li><li><span class="mx-2">/</span></li><li>Viaje</li></ol></nav><div class="bg-white rounded-xl shadow-lg p-8 max-w-4xl mx-auto"><div class="text-center mb-8"><h1 class="text-5xl font-bold text-gray-900 mb-4"><?php echo esc_html($origen); ?> <span class="text-primary">→</span> <?php echo esc_html($destino); ?></h1><p class="text-xl text-gray-600"><?php echo date_i18n('l, d F Y', strtotime($fecha)); ?> a las <?php echo esc_html($hora); ?></p></div><div class="grid md:grid-cols-2 gap-8 mb-8"><div class="bg-gray-50 rounded-lg p-6"><h3 class="text-lg font-bold mb-4">Detalles del viaje</h3><dl class="space-y-3"><div><dt class="text-sm font-semibold text-gray-700">Origen:</dt><dd class="text-gray-900"><?php echo esc_html($origen); ?></dd></div><div><dt class="text-sm font-semibold text-gray-700">Destino:</dt><dd class="text-gray-900"><?php echo esc_html($destino); ?></dd></div><div><dt class="text-sm font-semibold text-gray-700">Fecha y hora:</dt><dd class="text-gray-900"><?php echo date_i18n('d/m/Y', strtotime($fecha)); ?> - <?php echo esc_html($hora); ?></dd></div><div><dt class="text-sm font-semibold text-gray-700">Plazas disponibles:</dt><dd class="text-gray-900 font-bold text-xl"><?php echo esc_html($plazas); ?></dd></div></dl></div><div class="bg-primary bg-opacity-10 rounded-lg p-6"><h3 class="text-lg font-bold mb-4">Información del conductor</h3><div class="flex items-center gap-3 mb-4"><?php echo get_avatar($conductor_id, 60, '', '', array('class' => 'rounded-full')); ?><div><p class="font-bold text-lg"><?php echo get_the_author(); ?></p><p class="text-sm text-gray-600">Conductor verificado</p></div></div><div class="text-4xl font-bold text-primary mb-4"><?php echo esc_html($precio); ?>€<span class="text-base font-normal text-gray-600">/plaza</span></div><?php if (is_user_logged_in() && get_current_user_id() !== $conductor_id) : ?><button class="w-full px-6 py-3 bg-primary text-white rounded-lg hover:bg-primary-dark font-bold">Reservar Plaza</button><?php elseif (!is_user_logged_in()) : ?><a href="<?php echo wp_login_url(get_permalink()); ?>" class="block text-center w-full px-6 py-3 bg-primary text-white rounded-lg font-bold">Inicia sesión para reservar</a><?php endif; ?></div></div><div class="prose max-w-none mb-8"><h2 class="text-2xl font-bold mb-4">Descripción</h2><?php the_content(); ?></div></div></div><?php endwhile; get_footer(); ?>
